    methods: {
        handleBuy(i) {
            this.showProductModal = true;
            this.currentIndex = i;
        },
        closeProductModal() {
            this.showProductModal = false;
        },
        closeaddModal() {
            this.$emit('close');
        },
        add(product) {
            this.$emit('addTocart', { ...product });
        },
        eaddsacart(product) {
            this.$emit('addTocart', product);
        }
    }
